  contact
    "
     E-mail: nkaliape@gmail.com";

  description 
    "This module contains a set of deviations of the openconfig-platform module";

  revision "2018-05-10" {
    description
      "Initial revision";
  }

  deviation /oc-platform:components/oc-platform:component/oc-platform:subcomponents/oc-platform:subcomponent {
    deviate "not-supported"; 
  }
  deviation /oc-platform:components/oc-platform:component/oc-platform:subcomponents/oc-platform:subcomponent/oc-platform:name {
    deviate "not-supported"; 
  }
}_

(testenv) nkaliape@narayan-vm:~/testany/oc_yang_collection$ pyang --lax-quote-checks --plugindir $PYBINDPLUGIN -f  tree -o test.tree report_bug.yang
report_bug.yang:34: error: node openconfig-platform::subcomponent is not found

